import { getTransitionSizes } from '@formkit/auto-animate';

interface Coordinates {
  top: number;
  left: number;
  width: number;
  height: number;
}

interface Keyframe {
  composite?: CompositeOperationOrAuto;
  easing?: string;
  offset?: number | null;
  [property: string]: string | number | null | undefined;
}

export function fade(options?: number | KeyframeEffectOptions | undefined) {
  return function (
    el: Element,
    action: 'add' | 'remove' | 'remain',
    newCoordinates: Coordinates,
    oldCoordinates: Coordinates,
  ): KeyframeEffect {
    let keyframes: Keyframe[] = [];
    // supply a different set of keyframes for each action
    if (action === 'add') {
      keyframes = [{ opacity: 0 }, { opacity: 1 }];
      options ??= { duration: 300, easing: 'ease-in' };
    }
    // keyframes can have as many "steps" as you prefer
    // and you can use the 'offset' key to tune the timing
    if (action === 'remove') {
      keyframes = [
        {
          opacity: 1,
        },
        {
          opacity: 0,
        },
      ];
      options ??= { duration: 300, easing: 'ease-out' };
    }
    if (action === 'remain') {
      // for items that remain, calculate the delta
      // from their old position to their new position
      const deltaX = oldCoordinates.left - newCoordinates.left;
      const deltaY = oldCoordinates.top - newCoordinates.top;
      // use the getTransitionSizes() helper function to
      // get the old and new widths of the elements
      const [widthTo, widthFrom, heightTo, heightFrom] = getTransitionSizes(
        el,
        oldCoordinates,
        newCoordinates,
      );
      // set up our steps with our positioning keyframes
      const start: Keyframe = {
        transform: `translate(${deltaX}px, ${deltaY}px)`,
      };
      const end: Keyframe = { transform: `translate(0, 0)` };
      // if the dimensions changed, animate them too.
      if (widthFrom !== widthTo) {
        start.width = `${widthFrom}px`;
        end.width = `${widthTo}px`;
      }
      if (heightFrom !== heightTo) {
        start.height = `${heightFrom}px`;
        end.height = `${heightTo}px`;
      }
      keyframes = [start, end];
      options ??= { duration: 300, easing: 'ease-in-out' };
    }
    // return our KeyframeEffect() and pass
    // it the chosen keyframes.
    return new KeyframeEffect(el, keyframes, options);
  };
}

export function normal(options?: number | KeyframeEffectOptions | undefined) {
  return function (
    el: Element,
    action: 'add' | 'remove' | 'remain',
    newCoordinates: Coordinates,
    oldCoordinates: Coordinates,
  ): KeyframeEffect {
    let keyframes: Keyframe[] = [];
    // supply a different set of keyframes for each action
    if (action === 'add') {
      keyframes = [
        { transform: 'scale(.98)', opacity: 0 },
        { transform: 'scale(0.98)', opacity: 0, offset: 0.5 },
        { transform: 'scale(1)', opacity: 1 },
      ];
      options ??= { duration: 300, easing: 'ease-in' };
    }
    // keyframes can have as many "steps" as you prefer
    // and you can use the 'offset' key to tune the timing
    if (action === 'remove') {
      keyframes = [
        {
          transform: 'scale(1)',
          opacity: 1,
        },
        {
          transform: 'scale(.98)',
          opacity: 0,
        },
      ];
      options ??= { duration: 300, easing: 'ease-out' };
    }
    if (action === 'remain') {
      // for items that remain, calculate the delta
      // from their old position to their new position
      const deltaX = oldCoordinates.left - newCoordinates.left;
      const deltaY = oldCoordinates.top - newCoordinates.top;
      // use the getTransitionSizes() helper function to
      // get the old and new widths of the elements
      const [widthTo, widthFrom, heightTo, heightFrom] = getTransitionSizes(
        el,
        oldCoordinates,
        newCoordinates,
      );
      // set up our steps with our positioning keyframes
      const start: Keyframe = {
        transform: `translate(${deltaX}px, ${deltaY}px)`,
      };
      const end: Keyframe = { transform: `translate(0, 0)` };
      // if the dimensions changed, animate them too.
      if (widthFrom !== widthTo) {
        start.width = `${widthFrom}px`;
        end.width = `${widthTo}px`;
      }
      if (heightFrom !== heightTo) {
        start.height = `${heightFrom}px`;
        end.height = `${heightTo}px`;
      }
      keyframes = [start, end];
      options ??= { duration: 300, easing: 'ease-in-out' };
    }
    // return our KeyframeEffect() and pass
    // it the chosen keyframes.
    return new KeyframeEffect(el, keyframes, options);
  };
}

export function bouncy(
  options: number | KeyframeEffectOptions | undefined = {
    duration: 300,
    easing: 'ease-in-out',
  },
) {
  return function (
    el: Element,
    action: 'add' | 'remove' | 'remain',
    newCoordinates: Coordinates,
    oldCoordinates: Coordinates,
  ): KeyframeEffect {
    let keyframes: Keyframe[] = [];
    // supply a different set of keyframes for each action
    if (action === 'add') {
      keyframes = [
        { transform: 'scale(0)', opacity: 0 },
        { transform: 'scale(1.15)', opacity: 1, offset: 0.75 },
        { transform: 'scale(1)', opacity: 1 },
      ];
    }
    // keyframes can have as many "steps" as you prefer
    // and you can use the 'offset' key to tune the timing
    if (action === 'remove') {
      keyframes = [
        { transform: 'scale(1)', opacity: 1 },
        { transform: 'scale(1.15)', opacity: 1, offset: 0.33 },
        { transform: 'scale(0.75)', opacity: 0.1, offset: 0.5 },
        { transform: 'scale(0.5)', opacity: 0 },
      ];
    }
    if (action === 'remain') {
      // for items that remain, calculate the delta
      // from their old position to their new position
      const deltaX = oldCoordinates.left - newCoordinates.left;
      const deltaY = oldCoordinates.top - newCoordinates.top;
      // use the getTransitionSizes() helper function to
      // get the old and new widths of the elements
      const [widthFrom, widthTo, heightFrom, heightTo] = getTransitionSizes(
        el,
        oldCoordinates,
        newCoordinates,
      );
      // set up our steps with our positioning keyframes
      const start: Keyframe = {
        transform: `translate(${deltaX}px, ${deltaY}px)`,
      };
      const mid: Keyframe = {
        transform: `translate(${deltaX * -0.15}px, ${deltaY * -0.15}px)`,
        offset: 0.75,
      };
      const end: Keyframe = { transform: `translate(0, 0)` };
      // if the dimensions changed, animate them too.
      if (widthFrom !== widthTo) {
        start.width = `${widthFrom}px`;
        mid.width = `${
          widthFrom >= widthTo ? widthTo / 1.05 : widthTo * 1.05
        }px`;
        end.width = `${widthTo}px`;
      }
      if (heightFrom !== heightTo) {
        start.height = `${heightFrom}px`;
        mid.height = `${
          heightFrom >= heightTo ? heightTo / 1.05 : heightTo * 1.05
        }px`;
        end.height = `${heightTo}px`;
      }
      keyframes = [start, mid, end];
    }
    // return our KeyframeEffect() and pass
    // it the chosen keyframes.
    return new KeyframeEffect(el, keyframes, options);
  };
}
